		/// <summary>
		/// Constructor de la clase
		/// </summary>
		/// <param name="unidades">Una lista que contiene las unidades seleccionadas</param>
		public Grupo(List<Unidad> unidades)
		{

            m_idGrupo = s_random.Next(0, MAX_ID_GRUPO);

			if (unidades == null)
			{
				return;
			}

			m_unidades = unidades;
			m_velocidad = 100;

			m_promedioPuntosDeResistencia = 0;

			foreach (Unidad unidad in unidades)
			{
                unidad.AdherirmeAGrupo(this);

				if (unidad.Velocidad.X < m_velocidad)
				{
					m_velocidad = unidad.Velocidad.X;
				}
				m_promedioPuntosDeResistencia += unidad.PuntosDeResistencia;
			}

            //m_estado = ESTADO.ESPERANDO_ORDEN;
			m_promedioPuntosDeResistencia = m_promedioPuntosDeResistencia / m_unidades.Count;
		}

		/// <summary>
		/// Mueve las unidades a la posicion deseada, formando un cuadrado.
		/// </summary>
		private void MoverUnidadesAPosicionesDeseadas()
		{
			const int IZQ = 0;
			const int ARR = 1;
			const int DER = 2;
			const int ABJ = 3;

			const int INCREMENTO_ESPIRAL = 2;
			const int INCREMENTO_UNIDADES = 2;

			int x = m_comandante.PosicionEnTileFisico.X;
			int y = m_comandante.PosicionEnTileFisico.Y;

			int i = 0;
			int j = 0;
			int inc = INCREMENTO_ESPIRAL;

			int cant = m_unidades.Count;


			//m_comandante.OffsetEnFormacion = new Point(0 ,0);
			m_comandante.OffsetEnFormacion = new Point(i, j);


			int dir = ARR;

			int puestos = 1;
			int indice = 0;

			//Recorro el mapa en forma de espiral apra encontrar una posicion cercana...
			while (puestos != cant)
			{
				if (s_mapa.EsPosicionCaminable(x + i, y + j) && m_unidades[indice] != m_comandante)
				{
					//Le determino el offset
					m_unidades[indice].OffsetEnFormacion = new Point(i, j);

					//Lo muevo a donde tiene que ir..
					m_unidades[indice].Mover(x + i, y + j);
					m_unidades[indice].SetearOrdenDeObjetivo(m_ordenObjetivo);
					puestos++;
					indice++;
				}
				else if (m_unidades[indice] == m_comandante)
				{
					m_comandante.Parar();
					indice++;
				}
				

				if (dir == ARR)
				{
					i += INCREMENTO_UNIDADES;
					if (i == inc)
					{
						dir = DER;
						continue;
					}
				}

				if (dir == DER)
				{
					j += INCREMENTO_UNIDADES;

					if (j == inc)
					{
						dir = ABJ;

						continue;
					}
				}

				if (dir == IZQ)
				{
					j -= INCREMENTO_UNIDADES;
					if (j == -inc)
					{
						dir = ARR;
						inc += INCREMENTO_ESPIRAL;
						continue;
					}
				}

				if (dir == ABJ)
				{
					i -= INCREMENTO_UNIDADES;
					if (i == -inc)
					{
						dir = IZQ;
						continue;
					}
				}
			}
		}

		/// <summary>
		/// Actualiza toda la grupo.
		/// </summary>
		public void Actualizar()
		{

            Log.Instancia.Debug("Estado: " + m_estado);

			switch (m_estado)
			{
				case ESTADO.ESPERANDO_ORDEN:
					ActualizarEstadoEsperandoOrden();
					break;

				case ESTADO.MOVIENDO:
					ActualizarEstadoMoviendo();
					break;

				case ESTADO.AGRUPANDO:
					ActualizarEstadoAgrupando();
                    break;

                case ESTADO.PERSIGUIENDO_ENEMIGO:
                    ActualizarEstadoPersiguiendoEnemgigo();
                    break;

				case ESTADO.ATANCANDO:
					ActualizarEstadoAtacando();
					break;

				case ESTADO.SANANDO:
					ActualizarEstadoSanando() ;
					break;

                case ESTADO.ELIMINADO:
                    return;
			}


			ChequearSaludCumplioOrden();
			EliminarUnidadesMuertas();

            if (m_unidades.Count <= 1)
            {
                SetearEstado(ESTADO.ELIMINADO);
            }

                

            if (m_comandante != null && m_comandante.EstaMuerto())
            {
                Log.Instancia.Debug("El comandante esta muerto, seteo uno nuevo.");
                SetearComandanteAuxiliar();
            }

			return;
		}

