		/// <summary>
		/// Actualiza las unidades sanandose.
		/// </summary>
		private void ActualizarEstadoSanando()
		{
			bool cumplio = true;
			foreach (Unidad unidad in m_unidades)
			{
				if (unidad.Salud != unidad.PuntosDeResistencia)
				{
					cumplio = false;
				}
			}

			if (cumplio)
			{
				Log.Instancia.Debug("Todos estan sanos...");
				SetearEstado(ESTADO.ESPERANDO_ORDEN);
			}
		}

		/// <summary>
		/// Chequea si el grupo cumplio la orden recibida.
		/// </summary>
		private void ChequearSaludCumplioOrden()
		{
			if (m_ordenRecibida == null)
			{
				Log.Instancia.Debug("El grupo no tiene ninguna orden seteada.");
				return;
			}

			m_promedioSalud = 0;
			foreach (Unidad unit in m_unidades)
			{
				m_promedioSalud += unit.Salud;

				switch (m_ordenRecibida.Id)
				{
					case Orden.TIPO.MOVER:
						if (unit.CumplioOrdenObjetivoMover())
						{
							Log.Instancia.Debug("El grupo cumplio la orden.");
							m_cumplioOrden = true;
						
						}
						break;
				}
			}

            if (m_unidades.Count > 0)
            {
                m_promedioSalud = m_promedioSalud / m_unidades.Count;
                if (m_cumplioOrden)
                {
                    SetearEstado((int)ESTADO.ESPERANDO_ORDEN);
                }
            }
            else
            {
                m_promedioSalud = 0;
            }
		}

		/// <summary>
		/// Elimino las unidades que se murieron del
		/// </summary>
		private void EliminarUnidadesMuertas()
		{
			List<Unidad> muertos = new List<Unidad>();
			m_promedioSalud = 0;

			foreach (Unidad unidad in m_unidades)
			{
				if (unidad.EstaMuerto())
				{
					muertos.Add(unidad);
				}
				else
				{
					m_promedioSalud += unidad.Salud;
				}
			}

			if (muertos.Count > 0)
			{
				foreach (Unidad unimuerto in muertos)
				{
                    //if (unimuerto == m_comandante)
                    //{
                    //    SetearComandanteAuxiliar();
                    //}
					m_unidades.Remove(unimuerto);
				}

				m_promedioPuntosDeResistencia = 0;

				if (m_unidades.Count != 0)
				{
					foreach (Unidad unidades in m_unidades)
					{
						m_promedioPuntosDeResistencia += unidades.PuntosDeResistencia;
					}

					m_promedioPuntosDeResistencia = m_promedioPuntosDeResistencia / m_unidades.Count;
				}
			}

            if (m_unidades.Count != 0)
            {
                m_promedioSalud = m_promedioSalud / m_unidades.Count;
            }
            else
            {
                m_promedioSalud = 0;
            }
		}

		/// <summary>
		/// Chequea si el grupo no recibio una nueva orden.
		/// </summary>
		private void ActualizarEstadoEsperandoOrden()
		{
			//me fijo si el grupo tiene inteligencia.
			if (m_inteligencia != null)
			{
				if (m_ordenRecibida == null)
				{
					m_ordenRecibida = m_inteligencia.ProximaOrden();
				}

				if (m_ordenRecibida != null && m_ordenRecibida.Id == Orden.TIPO.MOVER)
				{
					SetearOrdenObjetivo(Orden.TIPO.MOVER, m_ordenRecibida.Punto.X, m_ordenRecibida.Punto.Y);
					Mover(m_ordenRecibida.Punto.X, m_ordenRecibida.Punto.Y);
				}
			}
		}

