		/// <summary>
		/// Setea un comandante mas porque el anterior se murio.
		/// </summary>
		private void SetearComandanteAuxiliar()
		{
            if (m_unidades.Count >= 2)
            {
                m_comandante = m_unidades[0];
                m_comandante.MarcarComoComandante();
            }
		}

		/// <summary>
		/// Actualiza el estado formando. Estado en el que se encuentra el grupo 
		/// cuando esta tratando de formar el cuadrado
		/// </summary>
		private void ActualizarEstadoAgrupando()
		{
			//Chequea que las unidades esten en las posiciones deseadas. 
			//Si todas las unidades estan en ocio, entonces
			foreach (Unidad unidad in m_unidades)
			{
				if (unidad.EstadoActual != (int)Unidad.ESTADO.OCIO)
				{
                    Log.Instancia.Debug("Estado actual unidad: " + unidad.EstadoActual);

					return;
				}
			}

			//Si la orden recibida es la orden mover
            if (m_ordenRecibida != null && (m_ordenRecibida.Id == Orden.TIPO.MOVER || m_ordenRecibida.Id == Orden.TIPO.SANAR))
			{
				m_comandante.Mover(m_tileObjetivo.X, m_tileObjetivo.Y);
				if (m_comandante.CaminoASeguir == null)
				{
					//BUG FIX.
					SetearEstado(ESTADO.ESPERANDO_ORDEN);
					return;
				}

				SetearEstado(ESTADO.MOVIENDO);

				foreach (Unidad unidad in m_unidades)
				{
					unidad.CalcularCaminoADistancia(m_comandante.CaminoASeguir, unidad.OffsetEnFormacion.X, unidad.OffsetEnFormacion.Y);
				}
			}
		}

