		/// <summary>
		/// Actualiza el estado moviendo de la formación.
		/// </summary>
		private void ActualizarEstadoMoviendo()
		{
			bool todosEnOcio = true;

			foreach (Unidad unidad in m_unidades)
			{

                //Me fijo si todas las unidades estan en ocio.
				if (unidad.EstadoActual != Unidad.ESTADO.OCIO)
				{
                    if (m_ordenRecibida.Id == Orden.TIPO.SANAR)
                    {
                        if (unidad.EstadoActual != Unidad.ESTADO.SANANDO)
                        {
                            todosEnOcio = false;
                        }
                    }
                    else
                    {
						todosEnOcio = false;
                    }
				}
				else 
				{
                    if (m_ordenRecibida.Id == Orden.TIPO.SANAR)
                    {
                        if (unidad.Salud != unidad.PuntosDeResistencia)
                        {
                            Log.Instancia.Debug("Me dicen ue me sane..");
                            unidad.RecuperarSalud();
                        }
                    }
				}
			}

			if (todosEnOcio)
			{
				Log.Instancia.Debug("Todos en ocio!!!!");
				SetearEstado(m_proximoEstado);
			}
		}

