		/// <summary>
		/// Mueve toda la formación
		/// </summary>
		/// <param name="x">El punto x a donde se tiene que mover la grupo.</param>
		/// <param name="y">El punto y a donde se tiene que mover la grupo</param>
		public void Mover(int x, int y)
		{
			m_ordenRecibida = new Orden(Orden.TIPO.MOVER, x, y);
			SetearEstado(ESTADO.AGRUPANDO);
			m_tileObjetivo = new Point(x, y);

			//Seteo el comandante, si no tiene seteado uno.
			if (m_comandante == null)
			{
				SetearComandante();
			}
			m_proximoEstado = ESTADO.ESPERANDO_ORDEN;

			MoverUnidadesAPosicionesDeseadas();
		}

		/// <summary>
