		private void SetearEstado(Grupo.ESTADO estado)
		{
			m_estado = estado;
			if (estado == ESTADO.ESPERANDO_ORDEN)
			{
				m_cumplioOrden = false;
				m_ordenRecibida = null;
			}
		}

