		/// <summary>
		/// Se le da a la formacion la orden de sanarse.
		/// </summary>
		public void Sanar(int x, int y)
		{
			m_ordenRecibida = new Orden(Orden.TIPO.SANAR, x, y);

            if (m_comandante == null)
            {
                SetearComandanteAuxiliar();
            }

            Point p = s_mapa.ObtenerPosicionEnLineaDeVision(x, m_comandante.PosicionEnTileFisico.X, y, m_comandante.PosicionEnTileFisico.Y);

            if (p.X == -1 || p.Y == -1)
            {
                Log.Instancia.Debug("No se puede mandar a sanar al grupo.");
                return;
            }

            SetearSanar(p.X, p.Y);
        }

        public int Id
        {
            get
            {
                return m_idGrupo;
            }

        }

        /// <summary>
		/// Setea el estado sanar;
		/// </summary>
		/// <param name="x">La posicion x en donde sanar.</param>
		/// <param name="y">La posicion y en donde sanar.</param>
		private void SetearSanar(int x, int y)
		{
			Mover(x, y);
            m_ordenRecibida = new Orden(Orden.TIPO.SANAR, x, y);
			m_proximoEstado = ESTADO.SANANDO;
		}

        public Unidad ObtenerUltimaUnidad()
        {
            if (m_unidades.Count == 1)
            {
                return m_unidades[0];
            }
            return null;
        }

        public void EliminarGrupo()
        {
            foreach (Unidad unidad in m_unidades)
            {
                unidad.SalirDelGrupo();
            }
        }

        public void EliminarUnidad(Unidad unidad)
        {
            m_unidades.Remove(unidad);

            if (unidad == m_comandante)
            {
                m_comandante = null;
                unidad.DesmarcarComandante();

                SetearComandanteAuxiliar();
            }

            if (m_unidades.Count <= 1)
            {
                SetearEstado(ESTADO.ELIMINADO);
            }
        }
    }//end grupo

}//end namespace Nivel